ee:message.ee:set-payload:
%dw 2.0
output application/json
// Alias the deep path once so the mapping below stays readable. `.` navigation is null-safe in DataWeave:
// if `profileDetails` is missing, `p.customer.gender` is just null rather than an error.
var p = vars.currentResource.profileDetails
---
{
    // profileIdList[0].id is the OPERA internal profileId echoed back; fall back to the event's primaryKey.
    profileId: vars.currentResource.profileIdList[0].id default vars.businessEvent.primaryKey,
    profileType: p.profileType,          // Guest | Company | Agent | ...
    status: p.statusCode,                // Active | Inactive

    // personName is an array (max 5: primary, alternate-language, ...). `default []` = safe map when absent.
    names: (p.customer.personName default []) map (n) -> {
        title:  n.namePrefix,
        first:  n.givenName,
        middle: n.middleName,
        last:   n.surname
    },

    // Contacts come wrapped in a collection. filter to the primary-flagged entry, take the first ([0]).
    // (`== true` keeps this null-safe: a bare boolean field in filter throws when the flag is absent.)
    primaryEmail: ((p.emails.emailInfo default []) filter ($.email.primaryInd == true))[0].email.emailAddress,
    primaryPhone: ((p.telephones.telephoneInfo default []) filter ($.telephone.primaryInd == true))[0].telephone.phoneNumber,

    demographics: {
        gender:      p.customer.gender,
        birthDate:   p.customer.birthDate,      // "YYYY-MM-DD"
        nationality: p.customer.nationality,
        vipStatus:   p.customer.vipStatus
    },

    audit: {
        createdAt: p.createDateTime,
        updatedAt: p.lastModifyDateTime
    }
}

%dw 2.0
// =====================================================================================================
// EXAMPLE — accessing getReservation fields in a Transform Message
// -----------------------------------------------------------------------------------------------------
// Source call : GET /rsv/v1/hotels/{hotelId}/reservations/{reservationId}  (operationId getReservation, rsv.json)
// Response    : the `reservation` definition — a COLLECTION wrapper even for a single id. Paths from rsv.json:
//                 reservation
//                   .reservations.reservation[]            (hotelReservationType)
//                       .reservationIdList[]               (uniqueID_Type: {id, type, idExtension})
//                       .hotelId
//                       .reservationStatus                 (enum: Reserved | InHouse | CheckedOut | Cancelled | ...)
//                       .roomStay                          (roomStayType)
//                           .arrivalDate / .departureDate
//                           .guestCounts.adults/.children  (guestCountsType)
//                           .currentRoomInfo.roomType/.roomId (currentRoomInfoType)
//                           .total                          (totalType: amountBeforeTax, amountAfterTax, currencyCode)
//                           .roomRates[]                    (roomRateType: ratePlanCode, roomType, start, end, total)
//                       .reservationGuests[]               (resGuestType)
//                           .primary
//                           .profileInfo.profileIdList[]    (uniqueID_Type)
//                           .profileInfo.profile.customer.personName[] (same customerType as CRM)
//                       .createDateTime / .lastModifyDateTime
//
// How to use: at the [PLUG-IN] point the getReservation body is in `vars.currentResource`. The single
//             reservation is reservations.reservation[0]. Use `payload` instead if you transform inline.
//
// ponytail: roomRates, reservationGuests, totals, packages etc. are populated ONLY when the matching
//           getReservation `fetchInstructions` are sent (Reservation, RateInfoDetails, DailySummary, ...).
//           Without them the response is sparse — every deep path here is null-safe (default []/null).
// =====================================================================================================
output application/json
// The response is a COLLECTION wrapper even for one id; alias the single reservation once. `.` navigation
// is null-safe, so deep reads below yield null (not an error) when a section wasn't fetched.
var r = vars.currentResource.reservations.reservation[0]
---
{
    reservationId: r.reservationIdList[0].id default vars.businessEvent.primaryKey,
    hotelId:       r.hotelId default vars.businessEvent.hotelId,
    status:        r.reservationStatus,     // Reserved | InHouse | CheckedOut | Cancelled | ...

    stay: {
        arrival:        r.roomStay.arrivalDate,     // "YYYY-MM-DD"
        departure:      r.roomStay.departureDate,
        adults:         r.roomStay.guestCounts.adults,
        children:       r.roomStay.guestCounts.children,
        roomType:       r.roomStay.currentRoomInfo.roomType,
        roomNumber:     r.roomStay.currentRoomInfo.roomId,
        // roomStay.total (totalType): amounts are Numbers, currencyCode is ISO 4217.
        totalBeforeTax: r.roomStay.total.amountBeforeTax,
        totalAfterTax:  r.roomStay.total.amountAfterTax,
        currency:       r.roomStay.total.currencyCode
    },

    // roomRates[] — one entry per rate-plan / room-type / date-range combination.
    rates: (r.roomStay.roomRates default []) map (rr) -> {
        ratePlan:       rr.ratePlanCode,
        roomType:       rr.roomType,
        from:           rr.start,
        to:             rr.end,
        amountAfterTax: rr.total.amountAfterTax,
        currency:       rr.total.currencyCode
    },

    // reservationGuests[] -> profileInfo.profile.customer.personName[] (same customerType as the CRM profile).
    guests: (r.reservationGuests default []) map (g) -> {
        primary:   g.primary default false,
        profileId: g.profileInfo.profileIdList[0].id,
        first:     g.profileInfo.profile.customer.personName[0].givenName,
        last:      g.profileInfo.profile.customer.personName[0].surname
    },

    audit: {
        createdAt: r.createDateTime,
        updatedAt: r.lastModifyDateTime
    }
}
